PlayerListener = {}

function PlayerListener:init()
    PlayerUseInitSpawnPositionEvent.registerCallBack(self.onPlayerUseInitSpawnPosition)
    --SyncEntityPlayerInfoEvent.registerCallBack(self.onSyncEntityPlayerInfo)
    PlayerMoveEvent.registerCallBack(self.onPlayerMove)
    PlayerAdvancedSuccessEvent:registerCallBack(self.onPlayerAdvancedSuccess)
    PlayerHealthChangedEvent.registerCallBack(self.onPlayerHealthChanged)
    ChangeMaxHealthSingleEvent.registerCallBack(self.onChangeMaxHealthSingle)
    PlayerReviewPlayerEvent.registerCallBack(self.onPlayerReviewPlayer)
    PlayerReviewActorNpcEvent.registerCallBack(self.onPlayerReviewActorNpc)
    --WrongMoveEvent.registerCallBack(self.onWrongMove)
    SendGuideInfoEvent.registerCallBack(self.onSendGuideInfo)
    CommonReceiveRewardEvent:registerCallBack(self.onCommonReceiveReward)
    ReceiveSumRechargeEndEvent:registerCallBack(self.onReceiveSumRechargeEnd)

    BaseListener.registerCallBack(PlayerLoginEvent, self.onPlayerLogin)
    BaseListener.registerCallBack(PlayerLogoutEvent, self.onPlayerLogout)
    BaseListener.registerCallBack(PlayerReadyEvent, self.onPlayerReady)
    BaseListener.registerCallBack(PlayerRespawnEvent, self.onPlayerRespawn)
    BaseListener.registerCallBack(PlayerAfterRespawnEvent, self.onPlayerAfterRespawn)
    BaseListener.registerCallBack(PlayerAttackedEvent, self.onPlayerHurt)
end

function PlayerListener.onPlayerUseInitSpawnPosition(userId, position)
    position.x = GameConfig.initPos.x
    position.y = GameConfig.initPos.y
    position.z = GameConfig.initPos.z
    return false
end

