function PlayerListener.onPlayerLogin(clientPeer)
    local player = GamePlayer.new(clientPeer)
    player:init()
    LogUtil.log(string.format("PlayerListener.onPlayerLogin %s", player.name))
    return GameOverCode.Success, player
end

function PlayerListener.onPlayerLogout(player)
    if player == nil then
        return
    end
    AreaManager:onPlayerLogout(player)
    LSRankManager:removePlayerRank(player.userId)
    player:onLogout()
end

function PlayerListener.onPlayerReady(player)
    LogUtil.log("PlayerListener.onPlayerReady")

    if player == nil then
        return
    end

    player:onReady()

    DbUtil:getPlayerData(player)

    return 43200
end

function PlayerListener.onPlayerRespawn(player)
    player:onRespawn()
    return 43200
end

function PlayerListener.onPlayerAfterRespawn(player)
    player:onAfterRespawn()
end

function PlayerListener.onPlayerHurt(hurtPlayer, hurtFrom, damageType, hurtValue)
    local hurter = PlayerManager:getPlayerByPlayerMP(hurtPlayer)
    if hurter == nil then
        return true
    end

    if damageType == "outOfWorld" then
        hurter:onHurt(nil, hurter.property:getMaxHealth(), true)
        return true
    end

    if CheckAreaRule:CheckAreaRule(hurter.Area, Define.AreaRule.NotAllowHurt) then
        return false
    end

    local attacker = PlayerManager:getPlayerByPlayerMP(hurtFrom)
    if attacker ~= nil then
        if CheckAreaRule:CheckAreaRule(attacker.Area, Define.AreaRule.NotAllowAttack) then
            return false
        end
    end

    hurter:bePlayerAttacked(attacker)

    return false
end

function PlayerListener.onPlayerMove(movePlayer, x, y, z)
    local player = PlayerManager:getPlayerByPlayerMP(movePlayer)
    if player == nil then
        return true
    end

    local position = VectorUtil.newVector3(x, y, z)
    AreaManager:checkPlayerPosition(player, position)
    TeamManager:onPlayerMove(player)
    return true
end

