function PlayerListener.onPlayerHealthChanged(playerMP, old_health, new_health)
    local player = PlayerManager:getPlayerByPlayerMP(playerMP)
    if not player then
        return
    end
    player:onHealthChanged(old_health, new_health)
end

function PlayerListener.onChangeMaxHealthSingle(entityId, maxHealth)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if not player then
        return
    end
    player:onChangeMaxHealthSingle(maxHealth)
end

function PlayerListener.onPlayerReviewPlayer(selfRakssid, targetRakssid)
    --print(string.format("PlayerListener.onPlayerReviewPlayer %s %s",
    --        tostring(selfRakssid), tostring(targetRakssid)))

    local selfPlayer = PlayerManager:getPlayerByRakssid(selfRakssid)
    local targetPlayer = PlayerManager:getPlayerByRakssid(targetRakssid)
    if not selfPlayer or not targetPlayer then
        return
    end
    selfPlayer:onReviewPlayer(targetRakssid)
end

function PlayerListener.onSendGuideInfo(rakssid, guideId, guideStatus)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return false
    end
    local guide = { Id = guideId, Status = guideStatus }
    GameGuide:updateStatus(player, guide)
end

